import os
import numpy as np
import cv2
import pickle
from flask import Flask, request, jsonify
from flask_limiter import Limiter
from flask_limiter.util import get_remote_address
from sklearn.preprocessing import LabelEncoder
from sklearn.svm import SVC
from sklearn.metrics.pairwise import cosine_similarity
import face_recognition
import hashlib
import secrets
from datetime import datetime, timedelta
import logging

app = Flask(__name__)
app.config['SECRET_KEY'] = secrets.token_hex(32)

# Configure logging
logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

# Security configuration
limiter = Limiter(
    app,
    key_func=get_remote_address,
    default_limits=["100 per hour"]
)

# Model storage
MODEL_DIR = "models"
os.makedirs(MODEL_DIR, exist_ok=True)

class FacialRecognitionAPI:
    def __init__(self):
        self.known_encodings = []
        self.known_names = []
        self.model = None
        self.label_encoder = None
        self.is_trained = False
        
    def _validate_image(self, image_path):
        """Validate image file"""
        if not os.path.exists(image_path):
            return False
        try:
            img = cv2.imread(image_path)
            if img is None:
                return False
            return True
        except Exception:
            return False
            
    def _extract_face_encodings(self, image_path):
        """Extract face encodings from image"""
        try:
            image = face_recognition.load_image_file(image_path)
            face_locations = face_recognition.face_locations(image)
            face_encodings = face_recognition.face_encodings(image, face_locations)
            return face_encodings
        except Exception as e:
            logger.error(f"Error extracting encodings from {image_path}: {e}")
            return []
            
    def train_model(self, employee_data):
        """Train model on employee photos"""
        self.known_encodings = []
        self.known_names = []
        
        for employee_name, image_paths in employee_data.items():
            for image_path in image_paths:
                if self._validate_image(image_path):
                    encodings = self._extract_face_encodings(image_path)
                    for encoding in encodings:
                        self.known_encodings.append(encoding)
                        self.known_names.append(employee_name)
        
        if len(self.known_encodings) == 0:
            raise ValueError("No valid face encodings found for training")
            
        # Encode labels
        self.label_encoder = LabelEncoder()
        encoded_names = self.label_encoder.fit_transform(self.known_names)
        
        # Train SVM model
        self.model = SVC(kernel='linear', probability=True)
        self.model.fit(self.known_encodings, encoded_names)
        self.is_trained = True
        
        # Save model
        self._save_model()
        
    def _save_model(self):
        """Save trained model to disk"""
        model_data = {
            'encodings': self.known_encodings,
            'names': self.known_names,
            'model': self.model,
            'label_encoder': self.label_encoder,
            'is_trained': self.is_trained
        }
        
        model_path = os.path.join(MODEL_DIR, 'facial_recognition_model.pkl')
        with open(model_path, 'wb') as f:
            pickle.dump(model_data, f)
            
    def _load_model(self):
        """Load trained model from disk"""
        model_path = os.path.join(MODEL_DIR, 'facial_recognition_model.pkl')
        if os.path.exists(model_path):
            try:
                with open(model_path, 'rb') as f:
                    model_data = pickle.load(f)
                self.known_encodings = model_data['encodings']
                self.known_names = model_data['names']
                self.model = model_data['model']
                self.label_encoder = model_data['label_encoder']
                self.is_trained = model_data['is_trained']
                return True
            except Exception as e:
                logger.error(f"Error loading model: {e}")
                return False
        return False
        
    def recognize_face(self, image_path):
        """Recognize faces in image and return confidence scores"""
        if not self.is_trained:
            if not self._load_model():
                raise ValueError("Model not trained and could not load existing model")
                
        try:
            # Extract face encodings from input image
            input_image = face_recognition.load_image_file(image_path)
            input_face_locations = face_recognition.face_locations(input_image)
            input_face_encodings = face_recognition.face_encodings(input_image, input_face_locations)
            
            results = []
            
            for face_encoding in input_face_encodings:
                # Get prediction probabilities
                probabilities = self.model.predict_proba([face_encoding])[0]
                predicted_class = self.model.predict([face_encoding])[0]
                predicted_name = self.label_encoder.inverse_transform([predicted_class])[0]
                
                # Create probability distribution
                class_names = self.label_encoder.classes_
                prob_dict = dict(zip(class_names, probabilities))
                
                # Calculate confidence score
                confidence = max(probabilities)
                
                results.append({
                    'name': predicted_name,
                    'confidence': float(confidence),
                    'probabilities': prob_dict,
                    'face_location': {
                        'top': int(input_face_locations[0][0]),
                        'right': int(input_face_locations[0][1]),
                        'bottom': int(input_face_locations[0][2]),
                        'left': int(input_face_locations[0][3])
                    }
                })
                
            return results
            
        except Exception as e:
            logger.error(f"Error in face recognition: {e}")
            raise

# Initialize API
face_api = FacialRecognitionAPI()

@app.route('/train', methods=['POST'])
@limiter.limit("5 per hour")
def train_model():
    """Train model with employee data"""
    try:
        data = request.get_json()
        employee_data = data.get('employee_data', {})
        
        if not employee_data:
            return jsonify({'error': 'No employee data provided'}), 400
            
        face_api.train_model(employee_data)
        return jsonify({'status': 'success', 'message': 'Model trained successfully'})
        
    except Exception as e:
        logger.error(f"Training error: {e}")
        return jsonify({'error': str(e)}), 500

@app.route('/recognize', methods=['POST'])
@limiter.limit("100 per hour")
def recognize_faces():
    """Recognize faces in uploaded image"""
    try:
        if 'image' not in request.files:
            return jsonify({'error': 'No image provided'}), 400
            
        file = request.files['image']
        if file.filename == '':
            return jsonify({'error': 'No image selected'}), 400
            
        # Save uploaded image temporarily
        temp_path = os.path.join(MODEL_DIR, f"temp_{datetime.now().timestamp()}.jpg")
        file.save(temp_path)
        
        # Perform recognition
        results = face_api.recognize_face(temp_path)
        
        # Clean up temp file
        os.remove(temp_path)
        
        return jsonify({
            'status': 'success',
            'results': results
        })
        
    except Exception as e:
        logger.error(f"Recognition error: {e}")
        return jsonify({'error': str(e)}), 500

